<?php
namespace Tests\Feature;use App\Models\Character;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class CharacterStatsDisplayTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}public function test_character_sheet_displays_effective_stats_and_power(){$user=User::factory()->create();$character=Character::factory()->selectedFor($user)->create();$this->actingAs($user)->get(route('characters.show',$character))->assertOk()->assertSee('Estadísticas del personaje')->assertSee('Reducción de daño efectiva')->assertSee('Poder 143');}public function test_character_sheet_separates_base_equipment_and_effective_stats(){$user=User::factory()->create();$character=Character::factory()->selectedFor($user)->create();$this->actingAs($user)->get(route('characters.show',$character))->assertSee('Estadística')->assertSee('Base')->assertSee('Equipamiento')->assertSee('Efectiva')->assertSee('Vida máxima')->assertSee('Ataque')->assertSee('Crítico');}public function test_user_still_cannot_view_another_users_character(){$owner=User::factory()->create();$character=Character::factory()->selectedFor($owner)->create();$this->actingAs(User::factory()->create())->get(route('characters.show',$character))->assertForbidden();}public function test_calculated_stats_are_not_persisted_as_columns(){foreach(['power','damage_reduction_rate','absorb_damage_basis_points','critical_damage_multiplier','attack_speed','loot_bonus','experience_bonus','gold_bonus']as$column)$this->assertNotContains($column,Schema::getColumnListing('characters'));}public function test_home_no_longer_calculates_unused_character_stats(){$user=User::factory()->create();Character::factory()->selectedFor($user)->create();$this->actingAs($user)->get('/')->assertOk()->assertViewHas('cards')->assertViewMissing('stats')->assertDontSee('Poder actual: 143');}public function test_character_sheet_displays_intermediate_experience_progress(){$user=User::factory()->create();$character=Character::factory()->selectedFor($user)->create(['level'=>2,'experience'=>140]);$this->actingAs($user)->get(route('characters.show',$character))->assertOk()->assertViewHas('experienceProgress')->assertSee('EXP acumulada')->assertSee('Progreso nivel 2 → 3')->assertSee('40 / 150 EXP')->assertSee('Faltan')->assertSee('110 EXP')->assertSee('26.67%');}public function test_character_sheet_displays_maximum_level_progress(){$user=User::factory()->create();$character=Character::factory()->selectedFor($user)->create(['level'=>5,'experience'=>920]);$this->actingAs($user)->get(route('characters.show',$character))->assertOk()->assertSee('Nivel máximo actual alcanzado')->assertSee('100%')->assertDontSee('Faltan');}}
